fun solve(n: Long, edges: Array<Array<Long>>, k: Long): Long {
    // Sort edges by their removal time
    edges.sortBy { it[2] }

    // Initialize parent array for Union-Find
    val parent = LongArray(n.toInt()) { it.toLong() }

    // Find function with path compression
    fun find(x: Long): Long {
        if (parent[x.toInt()] != x) {
            parent[x.toInt()] = find(parent[x.toInt()])
        }
        return parent[x.toInt()]
    }

    // Union function
    fun union(x: Long, y: Long) {
        val rootX = find(x)
        val rootY = find(y)
        if (rootX != rootY) {
            parent[rootY.toInt()] = rootX
        }
    }

    // Initially, all nodes are separate
    var components = n

    // Iterate through edges in order of removal time
    for (edge in edges) {
        val u = edge[0]
        val v = edge[1]
        val time = edge[2]

        // If the nodes are in different components, merge them
        if (find(u) != find(v)) {
            union(u, v)
            components--
        }

        // Check if we have at least k components
        if (components <= k) {
            return time
        }
    }

    // If we haven't found the answer, return the maximum time
    return edges.lastOrNull()?.let { it[2] } ?: 0L
}
